int yylex();
void yyerror(const char *s);
</pre>

%}

%union {
    char *str;
    int num;
}

%token IDENTIFIER INTEGER_LITERAL STRING_LITERAL
%token IF ELSE FOR WHILE FUNC RETURN
%token VAR LET
%token LPAREN RPAREN LBRACE RBRACE LBRACKET RBRACKET SEMICOLON COMMA
token PLUS MINUS MULTIPLY DIVIDE ASSIGN

%type <str> identifier
%type <num> integer_literal

%%

go_program: function_declaration_list;

function_declaration_list: function_declaration
                         | function_declaration_list function_declaration;

function_declaration: FUNC identifier LPAREN parameter_list RPAREN LBRACE statement_list RBRACE {
                        printf("Function declaration parsed\n");
                      };

parameter_list: /* empty */
               | identifier
               | parameter_list COMMA identifier;

statement_list: statement
               | statement_list statement;

statement: declaration_statement
          | expression_statement
          | if_statement
          | for_statement
          | while_statement
          | return_statement;

declaration_statement: VAR identifier ASSIGN expression SEMICOLON {
                        printf("Variable declaration parsed\n");
                      }
            | LET identifier ASSIGN expression SEMICOLON {
                        printf("Let declaration parsed\n");
                      };

expression_statement: expression SEMICOLON;

if_statement: IF LPAREN expression RPAREN LBRACE statement_list RBRACE {
               printf("If statement parsed\n");
             }
             | IF LPAREN expression RPAREN LBRACE statement_list RBRACE ELSE LBRACE statement_list RBRACE {
                 printf("If-else statement parsed\n");
               };

for_statement: FOR LPAREN expression SEMICOLON expression SEMICOLON expression RPAREN LBRACE statement_list RBRACE {
