        s ++= " %f".format(this(row,column))
      s ++= "\n"
  else 
    s ++= "[%d-by-%d matrix -- output suppressed]".format(m,n)
  s.toString

  /* Returns the transpose of this matrix as a new matrix.*/
def transpose : Matrix = 
  val result = new Matrix(n,m)
  for row <- 0 until m; column <- 0 until n do 
    result(column, row) = this(row, column)
  result

  /* Returns a new matrix that is the sum of this and that */
def +(that: Matrix) : Matrix = 
  require(m == that.m && n == that.n)
  val result = new Matrix(m,n)
  (0 until m*n).foreach(i => { result.entries(i) = this.entries(i) + that.entries(i) })
  result

  /* Returns a new matrix that negates the entries of this */
def unary_- : Matrix = 
  val result = new Matrix(m,n)
  (0 until m*n).foreach(i => { result.entries(i) = -entries(i) })
  result

  /* Returns a new matrix that is the difference of this and that */
def -(that: Matrix) : Matrix = 
  this + -that

  /* Returns a new matrix that is the product of 'this' and 'that' */
def *(that: Matrix): Matrix = 
  require(n == that.m)
  val thatT = that.transpose // transpose 'that' to get better cache-locality
  def inner(r1: Int, r2: Int) = 
    var s = 0.0
    var i = 0
    while i < n do // the inner loop -- here is where transposing 'that' pays off
      s = s + entries(r1+i)*thatT.entries(r2+i)
      i = i+1
    s
  val result = new Matrix(m,that.n)
  (0 until m*that.n).foreach(i => { result.entries(i) = inner((i/that.n)*n, (i%that.n)*n) })
  result

  /* * Task 1: * * Implement the following method that returns the multiplicative * inverse of this matrix. For example, you can use Gaussian elimination. * * Remark: * You may assume the matrix to be invertible and numerically well-behaved. * */
// Returns a new matrix that is the multiplicative inverse of this matrix.
def inverse: Matrix = 
  require(n == m) // create an augmented matrix [A | I]
  val augmented = new Matrix(m, 2 * n)
  (0 until m).foreach(i => { 
    (0 until n).foreach(j => { 
      augmented(i, j) = this(i, j)
      augmented(i, j + n) = if (i == j) 1 else 0 
    })
  })
  // perform Gauss-Jordan
  (0 until n).foreach(k => { 
    val pivot = augmented(k, k)
    (0 until 2 * n).foreach(j => { 
      augmented(k, j) = augmented(k, j) / pivot 
    })
    (0 until m).foreach(i => { 
      if (i != k) { 
        val factor = augmented(i, k)
        (0 until 2 * n).foreach(j => { 
          augmented(i, j) = augmented(i, j) - factor * augmented(k, j) 
        })
      }
    })
  })
  // extract the inverse matrix from the augmented matrix
  val inverse = new Matrix(n, n)
  (0 until n).foreach(i => { 
    (0 until n).foreach(j => { 
      inverse(i, j) = augmented(i, j + n) 
    })
  })
  inverse
end inverse
end Matrix

