void generateSubsequences(List<int> s, int SEQ_LENGTH, int SUB_LENGTH) {
  // Ensure the sequence length matches the expected length
  if (s.length != SEQ_LENGTH) {
    throw Exception('Sequence length does not match SEQ_LENGTH');
  }

  // Generate all possible subsequences of length SUB_LENGTH
  for (int i = 0; i <= SEQ_LENGTH - SUB_LENGTH; i++) {
    List<int> subsequence = [];
    for (int j = i; j < i + SUB_LENGTH; j++) {
      subsequence.add(s[j]);
    }

    // Print or process the subsequence
    print('Subsequence: $subsequence');

    // Add your processing logic here
  }
}

