/*
 * Solution for the terabyte stream processing problem
 */

package teraStream

class BlockStream(numblocks: Int, blocklength: Int) extends collection.AbstractIterator[Array[Long]]:
  val modulus = Array(0, 5, 8, 18, 22, 60).map(1L << _).foldLeft(0L)(_ | _ )
  val hi = 0x4000000000000000L
  val mask = 0x7FFFFFFFFFFFFFFFL
  val startval = 0xA3A3A3A3A3A3A3A3L & mask
  var current = startval
  var blockno = 0

  def rewind() : Unit = {
    current = startval
    blockno = 0
  }

  def hasNext: Boolean = blockno < numblocks

  def next(): Array[Long] = {
    require(blockno < numblocks)
    val blk = new Array[Long](blocklength)
    var i = 0
    while i < blocklength do {
      blk(i) = current
      if (current & hi) != 0L then
        current = ((current << 1) & mask) ^ modulus
      else
        current = current << 1
      i = i + 1
    }
    blockno = blockno + 1
    blk
  }

val inputStream = new BlockStream(1048576, 131072) // A one-terabyte stream
val practiceStream = new BlockStream(1024, 128) // A one-megabyte stream

/*
 * Task 1: Compute the minimum value in inputStream.
 */
def minStream(s: BlockStream): Long = {
  var minVal = Long.MaxValue
  s.rewind()
  while (s.hasNext) {
    val block = s.next()
    for (word <- block) {
      if (word < minVal) minVal = word
    }
  }
  minVal
}

val minValue = minStream(inputStream) // the minimum VALUE that you have computed

/*
 * Task 2: Compute the maximum value in inputStream.
 */
def maxStream(s: BlockStream): Long = {
  var maxVal = Long.MinValue
  s.rewind()
  while (s.hasNext) {
    val block = s.next()
    for (word <- block) {
      if (word > maxVal) maxVal = word
    }
  }
  maxVal
}

val maxValue = maxStream(inputStream) // the maximum VALUE that you have computed

/*
 * Task 3: Compute the value at a specific position in the sorted stream.
 */

def posStream(s: BlockStream, pos: Long): Long = {
  // For the large stream, we'll use binary search on the value range
  // First, we need to estimate the value range

  // We'll use a simple approach: count how many values are <= a given value
  // This requires multiple passes through the data

  // For efficiency, we'll use binary search on the value range
  // Start with a reasonable range
  var low = Long.MinValue
  var high = Long.MaxValue

  // Helper function to count elements <= a given value
  def countLessEqual(value: Long): Long = {
    var count: Long = 0
    s.rewind()
    while (s.hasNext) {
      val block = s.next()
      for (word <- block) {
        if (word <= value) count += 1
      }
    }
    count
  }

  // Binary search for the value at position pos
  while (low < high) {
    val mid = low + (high - low) / 2
    val count = countLessEqual(mid)

    if (count <= pos) {
      low = mid + 1
    } else {
      high = mid
    }
  }

  low
}

