```python
from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import List, Optional
import uuid
from datetime import datetime

app = FastAPI(title="Measurement API", description="API for managing measurements")

class Measurement(BaseModel):
    id: Optional[str] = None
    value: float
    unit: str
    timestamp: datetime = datetime.now()
    description: Optional[str] = None

measurements_db = {}

@app.get("/")
def read_root():
    return {"message": "Welcome to Measurement API"}

@app.post("/measurements", response_model=Measurement)
def create_measurement(measurement: Measurement):
    measurement.id = str(uuid.uuid4())
    measurements_db[measurement.id] = measurement
    return measurement

@app.get("/measurements", response_model=List[Measurement])
def get_measurements():
    return list(measurements_db.values())

@app.get("/measurements/{measurement_id}", response_model=Measurement)
def get_measurement(measurement_id: str):
    if measurement_id not in measurements_db:
        raise HTTPException(status_code=404, detail="Measurement not found")
    return measurements_db[measurement_id]

@app.put("/measurements/{measurement_id}", response_model=Measurement)
def update_measurement(measurement_id: str, updated_measurement: Measurement):
    if measurement_id not in measurements_db:
        raise HTTPException(status_code=404, detail="Measurement not found")

    # Update the measurement
    updated_measurement.id = measurement_id
    measurements_db[measurement_id] = updated_measurement
    return updated_measurement

@app.delete("/measurements/{measurement_id}")
def delete_measurement(measurement_id: str):
    if measurement_id not in measurements_db:
        raise HTTPException(status_code=404, detail="Measurement not found")

    del measurements_db[measurement_id]
    return {"message": "Measurement deleted successfully"}

