    private ObjectMapper mapper = new ObjectMapper().registerModule(new JavaTimeModule());
    private GameResult result = new GameResult();
    private String player1;
    private String player2;
    private static final int BOARD_SIZE = 5;
    private static final int WINNING_CONDITION = 3;
    private boolean gameEnded;
    private Square[][] board;
    private ObjectProperty<Square>[][] squareProperties;
    private ObjectProperty<Square> currentPlayer;

    /**
     * Constructs a new {@code BoardGameModel} object.
     * Initializes the board, square properties, and the current player.
     */
    public BoardGameModel() {
        board = new Square[BOARD_SIZE][BOARD_SIZE];
        squareProperties = new ObjectProperty[BOARD_SIZE][BOARD_SIZE];
        currentPlayer = new SimpleObjectProperty<>(Square.RED);
        initializeBoard();
        initializeSquareProperties();
    }

    /**
     * Writes the game result to JSON.
     *
     * @param result the game result to be written
     * @throws IOException if an error occurs while writing to JSON
     */
    private void writeToJson(GameResult result) throws IOException {
        result.setWinner(currentPlayer.get() == Square.RED ? player1 : player2);
        result.setPlayer1Name(player1);
        result.setPlayer2Name(player2);
        List<GameResult> resultList = new ArrayList<>();
        if (file.exists()) {
            try (FileReader reader = new FileReader(file)) {
                resultList = mapper.readValue(reader, new TypeReference<ArrayList<GameResult>>() {});
            }
        }
        resultList.add(result);
        try (FileWriter writer = new FileWriter(file)) {
            mapper.writeValue(writer, resultList);
        }
    }

    /**
     * Sets the names of the players.
     *
     * @param name1 the name of player 1
     * @param name2 the name of player 2
     */
    public void setNames(String name1, String name2) {
        player1 = name1;
        player2 = name2;
    }

    /**
     * Initializes the game board with empty squares.
     */
    private void initializeBoard() {
        for (int i = 0; i < BOARD_SIZE; i++) {
            for (int j = 0; j < BOARD_SIZE; j++) {
                board[i][j] = Square.NONE;
            }
        }
        result.setStartDate(LocalDateTime.now());
    }

    @SuppressWarnings("unchecked")
    private void initializeSquareProperties() {
        for (int i = 0; i < BOARD_SIZE; i++) {
            for (int j = 0; j < BOARD_SIZE; j++) {
                squareProperties[i][j] = new SimpleObjectProperty<>(Square.NONE);
            }
        }
    }

    /**
     * Makes a move on the game board at the specified row and column.
     *
     * @param row the row index
     * @param col the column index
     */
    public void makeMove(int row, int col) {
        try {
            if (!gameEnded && isValidMove(row, col)) {
                board[row][col] = currentPlayer.get();
                squareProperties[row][col].set(board[row][col]);

                // Update player counts
                if (currentPlayer.get() == Square.RED) {
                    result.player1count++;
                } else {
                    result.player2count++;
                }

                // Check win condition
                if (checkWin()) {
                    System.out.println("Player " + currentPlayer.get() + " loses!");
                    gameEnded = true;
                    result.setEndDate(LocalDateTime.now());
                } else if (checkDraw()) {
                    System.out.println("It's a draw!");
                    gameEnded = true;
                    result.setEndDate(LocalDateTime.now());
                } else {
                    // Switch player
                    currentPlayer.set(currentPlayer.get() == Square.RED ? Square.BLUE : Square.RED);
                }

                if (gameEnded) {
                    writeToJson(result);
                }
            }
        } catch (IOException e) {
            System.err.println("An error occurred while writing to JSON: " + e.getMessage());
        }
    }

    private boolean isValidMove(int row, int col) {
        return row >= 0 && row < BOARD_SIZE && col >= 0 && col < BOARD_SIZE && board[row][col] == Square.NONE;
    }

    /**
     * Checks if a player has won the game.
     *
     * @return {@code true} if a player has won, {@code false} otherwise
     */
    public boolean checkWin() {
        return checkRows() || checkColumns() || checkDiagonals();
    }

    private boolean checkRows() {
        for (int i = 0; i < BOARD_SIZE; i++) {
            int redCount = 0;
            int blueCount = 0;
            for (int j = 0; j < BOARD_SIZE; j++) {
                if (board[i][j] == Square.RED) {
                    redCount++;
                } else if (board[i][j] == Square.BLUE) {
                    blueCount++;
                }
            }
            if (redCount >= WINNING_CONDITION || blueCount >= WINNING_CONDITION) {
                return true;
            }
        }
        return false;
    }

    private boolean checkColumns() {
        for (int j = 0; j < BOARD_SIZE; j++) {
            int redCount = 0;
            int blueCount = 0;
            for (int i = 0; i < BOARD_SIZE; i++) {
                if (board[i][j] == Square.RED) {
                    redCount++;
                } else if (board[i][j] == Square.BLUE) {
                    blueCount++;
                }
            }
            if (redCount >= WINNING_CONDITION || blueCount >= WINNING_CONDITION) {
                return true;
            }
        }
        return false;
    }

    private boolean checkDiagonals() {
        // Check all possible diagonals
        return checkAllDiagonals();
    }

    private boolean checkAllDiagonals() {
        // Check all possible diagonals of length 3 or more
        for (int i = 0; i < BOARD_SIZE; i++) {
            for (int j = 0; j < BOARD_SIZE; j++) {
                // Check diagonal from top-left to bottom-right
                if (i + WINNING_CONDITION - 1 < BOARD_SIZE && j + WINNING_CONDITION - 1 < BOARD_SIZE) {
                    if (checkDiagonalFromTopLeft(i, j)) {
                        return true;
                    }
                }

                // Check diagonal from top-right to bottom-left
                if (i + WINNING_CONDITION - 1 < BOARD_SIZE && j - WINNING_CONDITION + 1 >= 0) {
                    if (checkDiagonalFromTopRight(i, j)) {
                        return true;
                    }
                }
            }
        }
        return false;
    }

    private boolean checkDiagonalFromTopLeft(int startRow, int startCol) {
        int redCount = 0;
        int blueCount = 0;
        for (int i = 0; i < WINNING_CONDITION; i++) {
            if (board[startRow + i][startCol + i] == Square.RED) {
                redCount++;
            } else if (board[startRow + i][startCol + i] == Square.BLUE) {
                blueCount++;
            }
        }
        return redCount >= WINNING_CONDITION || blueCount >= WINNING_CONDITION;
    }

    private boolean checkDiagonalFromTopRight(int startRow, int startCol) {
        int redCount = 0;
        int blueCount = 0;
        for (int i = 0; i < WINNING_CONDITION; i++) {
            if (board[startRow + i][startCol - i] == Square.RED) {
                redCount++;
            } else if (board[startRow + i][startCol - i] == Square.BLUE) {
                blueCount++;
            }
        }
        return redCount >= WINNING_CONDITION || blueCount >= WINNING_CONDITION;
    }

    /**
     * Checks if the game is a draw (all squares are filled).
     *
     * @return {@code true} if the game is a draw, {@code false} otherwise
     */
    public boolean checkDraw() {
        for (int i = 0; i < BOARD_SIZE; i++) {
            for (int j = 0; j < BOARD_SIZE; j++) {
                if (board[i][j] == Square.NONE) {
                    return false;
                }
            }
        }
        return true;
    }

    /**
     * Returns the square property at the specified row and column.
     *
     * @param row the row index
     * @param col the column index
     * @return the square property at the specified row and column
     */
    public ObjectProperty<Square> squareProperty(int row, int col) {
        return squareProperties[row][col];
    }

    /**
     * Resets the game board to its initial state.
     */
    public void resetBoard() {
        gameEnded = false;
        initializeBoard();
        initializeSquareProperties();
        currentPlayer.set(Square.RED);
    }

    /**
     * Returns the current player.
     *
     * @return the current player
     */
    public Square getCurrentPlayer() {
        return currentPlayer.get();
    }
}

