<button id="openModal">Open Modal</button>

<div id="myModal" class="modal">
    <div class="modal-content">
        <span class="close">&times;</span>
        <h2>Form Modal</h2>
        <form id="myForm">
            <div class="form-group">
                <label for="numberField">Number Field:</label>
                <input type="number" id="numberField" name="numberField">
                <div id="numberError" class="error"></div>
            </div>
            <div class="form-group">
                <label for="stringField">String Field:</label>
                <input type="text" id="stringField" name="stringField">
                <div id="stringError" class="error"></div>
            </div>
            <button type="submit" class="submit-btn">Submit</button>
        </form>
    </div>
</div>

<script>
    // Get modal elements
    const modal = document.getElementById('myModal');
    const openBtn = document.getElementById('openModal');
    const closeBtn = document.querySelector('.close');
    const form = document.getElementById('myForm');

    // Open modal
    openBtn.addEventListener('click', () => {
        modal.style.display = 'block';
    });

    // Close modal
    closeBtn.addEventListener('click', () => {
        modal.style.display = 'none';
    });

    // Close modal when clicking outside
    window.addEventListener('click', (e) => {
        if (e.target === modal) {
            modal.style.display = 'none';
        }
    });

    // Form validation
    form.addEventListener('submit', (e) => {
        e.preventDefault();

        // Reset errors
        document.getElementById('numberError').textContent = '';
        document.getElementById('stringError').textContent = '';

        let isValid = true;

        // Validate number field
        const numberField = document.getElementById('numberField');
        const numberValue = numberField.value.trim();

        if (numberValue === '') {
            document.getElementById('numberError').textContent = 'Number field is required.';
            isValid = false;
        } else if (isNaN(numberValue)) {
            document.getElementById('numberError').textContent = 'Please enter a valid number.';
            isValid = false;
        } else if (parseFloat(numberValue) < 0) {
            document.getElementById('numberError').textContent = 'Number must be positive.';
            isValid = false;
        }

        // Validate string field
        const stringField = document.getElementById('stringField');
        const stringValue = stringField.value.trim();

        if (stringValue === '') {
            document.getElementById('stringError').textContent = 'String field is required.';
            isValid = false;
        } else if (stringValue.length < 3) {
            document.getElementById('stringError').textContent = 'String must be at least 3 characters long.';
            isValid = false;
        }

        // If valid, process form
        if (isValid) {
            alert(`Form submitted!\nNumber: ${numberValue}\nString: ${stringValue}`);
            modal.style.display = 'none';
        }
    });
