```java
public class SocialNetwork {
    private DiGraph graph;
    private ArrayList<String> nodeNames;

    public SocialNetwork() {
        // Initialize with 10 nodes ( Abel through Jody )
        this.graph = new DiGraph(10);
        this.nodeNames = new ArrayList<>(Arrays.asList(
            "Abel", "Bina", "Cato", "Dana", "Eden", "Fern", "Geno", "Hedy", "Inez", "Jodi"
        ));
    }

    /**
     * COMPLETE THIS METHOD * takes the name of a person and should return an ArrayList of String objects, which contains
     * the names all the followers of person.
     * @param person - the name of the Person to check
     * @return */
    public ArrayList<String> broadcastsTo(String person){
        ArrayList<String> result = new ArrayList<>();
        int index = nodeNames.indexOf(person);
        if (index == -1) return result;

        // Find all nodes that have an edge TO the current person
        for (int i = 0; i < graph.getNumberOfNodes(); i++) {
            if (graph.hasEdge(i, index)) {
                result.add(nodeNames.get(i));
            }
        }
        return result;
    }

    /**
     * COMPLETE THIS METHOD * Method takes the name of a person starting a broadcasting a story (source) and the name of the person that the
     * story is broadcast to (target). * It uses the refactored depth first search to see if the story will get from the source to the target and
     * should return true if the story will get from the source to the target
     * and false if there is no path from the source to the target.
     * @param source - the name of the Person to check
     * @param target - the name of the target to check
     * @return true if the story will get from the source to the target and false if there is no path from the
     * source to the target. */
    public boolean canReach(String source, String target) {
        int startIndex = nodeNames.indexOf(source);
        int endIndex = nodeNames.indexOf(target);

        if (startIndex == -1 || endIndex == -1) return false;

        // Use the refactored DFS from Traversal class
        ArrayList<Integer> visitedNodes = new ArrayList<>();
        Stack theStack = new ArrayStack();

        // Mark the start as visited and put it in the stack
        visitedNodes.add(startIndex);
        theStack.push(startIndex);

        while(!theStack.isEmpty()){ 
            Integer item = (Integer) theStack.pop();

            // If we found the target
            if (item.equals(endIndex)) {
                return true;
            }

            // Mark all the neighbours of the item which have not been visited as visited and add them to the stack
            for (Integer neighbour : graph.adjacencyList[item]) {
                if (!visitedNodes.contains(neighbour)) {
                    visitedNodes.add(neighbour);
                    theStack.push(neighbour);
                }
            }
        }

        return false;
    }

    /**
     * COMPLETE THIS METHOD * Method takes the name of a person who has started a story and uses a breadth first search to return an
     * ArrayList of String objects that contains the names of all the person who will receive the story
     * broadcast by that person.
     * @param person name of the person to check
     * @return an ArrayList of String objects that contains the names of all the person who will receive the story */
    public ArrayList<String> receiversOf(String person){
        ArrayList<String> result = new ArrayList<>();
        int startIndex = nodeNames.indexOf(person);

        if (startIndex == -1) return result;

        // Use the refactored BFS from Traversal class
        ArrayList<Integer> visitedNodes = new ArrayList<>();
        Queue theQueue = new ArrayQueue();

        // Mark the start as visited and put it in the Queue
        visitedNodes.add(startIndex);
        theQueue.enqueue(startIndex);

        while(!theQueue.isEmpty()){ 
            Integer item = (Integer) theQueue.dequeue();

            // Add all neighbors to result (except the starting node itself)
            for (Integer neighbour : graph.adjacencyList[item]) {
                if (!visitedNodes.contains(neighbour)) {
                    visitedNodes.add(neighbour);
                    theQueue.enqueue(neighbour);
                    result.add(nodeNames.get(neighbour));
                }
            }
        }

        return result;
    }
}

