// Simple in-memory client state storage
struct ClientState {
    std::string username;
    std::chrono::steady_clock::time_point lastActive;
    bool isConnected = true;
};

// Global server state
std::unordered_map<std::string, ClientState> clientStates;
std::mutex stateMutex;

// Generate RSA key pair
void generateRSAKeys(RSA*& rsa, EVP_PKEY*& pkey) {
    rsa = RSA_new();
    BIGNUM* bn = BN_new();
    BN_set_word(bn, RSA_F4);
    RSA_generate_key_ex(rsa, 2048, bn, nullptr);

    pkey = EVP_PKEY_new();
    EVP_PKEY_assign_RSA(pkey, rsa);
}

// Generate certificate from private key
X509* generateCertificate(EVP_PKEY* pkey) {
    X509* cert = X509_new();
    X509_set_version(cert, 2);

    // Set serial number
    ASN1_INTEGER_set(X509_get_serialNumber(cert), 1);

    // Set validity period
    X509_gmtime_adj(X509_get_notBefore(cert), 0);
    X509_gmtime_adj(X509_get_notAfter(cert), 365 * 24 * 60 * 60);

    // Set subject name
    X509_NAME* name = X509_get_subject_name(cert);
    X509_NAME_add_entry_by_txt(name, "C", MBSTRING_ASC, (unsigned char*)"US", -1, -1, -1);
    X509_NAME_add_entry_by_txt(name, "O", MBSTRING_ASC, (unsigned char*)"GameServer", -1, -1, -1);
    X509_NAME_add_entry_by_txt(name, "CN", MBSTRING_ASC, (unsigned char*)"localhost", -1, -1, -1);

    X509_set_issuer_name(cert, name);
    X509_set_pubkey(cert, pkey);

    // Sign certificate
    X509_sign(cert, pkey, EVP_sha256());

    return cert;
}

int main() {
    // Initialize OpenSSL
    SSL_library_init();
    SSL_load_error_strings();
    OpenSSL_add_all_algorithms();

    // Generate server keys
    RSA* rsaKey = nullptr;
    EVP_PKEY* privateKey = nullptr;
    generateRSAKeys(rsaKey, privateKey);

    // Generate certificate
    X509* certificate = generateCertificate(privateKey);

    std::cout << "Server started with self-signed certificate\n";
    std::cout << "Public key pre-shared for authentication\n";

    // Simulate server running
    while (true) {
        // In a real implementation, this would handle QUIC connections
        std::this_thread::sleep_for(std::chrono::seconds(1));

        // Clean up expired clients
        std::lock_guard<std::mutex> lock(stateMutex);
        auto now = std::chrono::steady_clock::now();
        for (auto it = clientStates.begin(); it != clientStates.end();) {
            if (std::chrono::duration_cast<std::chrono::seconds>(now - it->second.lastActive).count() > 30) {
                it = clientStates.erase(it);
            } else {
                ++it;
            }
        }
    }

    // Cleanup
    X509_free(certificate);
    EVP_PKEY_free(privateKey);
    RSA_free(rsaKey);

    return 0;
}
```

