Here's a Talend job code to perform matching between two databases:

```java
// Talend Job: Database Matching
public class DatabaseMatching {
    public static void main(String[] args) {
        // Connection to source database
        String sourceUrl = "jdbc:postgresql://localhost:5432/source_db";
        String sourceUser = "user";
        String sourcePassword = "password";

        // Connection to target database
        String targetUrl = "jdbc:oracle://localhost:1521/target_db";
        String targetUser = "user";
        String targetPassword = "password";

        try {
            // Establish connections
            java.sql.Connection sourceConn = java.sql.DriverManager.getConnection(sourceUrl, sourceUser, sourcePassword);
            java.sql.Connection targetConn = java.sql.DriverManager.getConnection(targetUrl, targetUser, targetPassword);

            // Query source data
            java.sql.Statement sourceStmt = sourceConn.createStatement();
            java.sql.ResultSet sourceRs = sourceStmt.executeQuery("SELECT * FROM employees");

            // Query target data
            java.sql.Statement targetStmt = targetConn.createStatement();
            java.sql.ResultSet targetRs = targetStmt.executeQuery("SELECT * FROM employee_data");

            // Match records based on ID field
            while (sourceRs.next()) {
                String sourceId = sourceRs.getString("id");

                // Find matching record in target
                targetRs.beforeFirst();
                boolean found = false;
                while (targetRs.next()) {
                    if (targetRs.getString("employee_id").equals(sourceId)) {
                        System.out.println("Match found: Source ID " + sourceId + " matches Target ID " + targetRs.getString("employee_id"));
                        found = true;
                        break;
                    }
                }

                if (!found) {
                    System.out.println("No match found for source ID: " + sourceId);
                }
            }

            // Close connections
            sourceRs.close();
            targetRs.close();
            sourceStmt.close();
            targetStmt.close();
            sourceConn.close();
            targetConn.close();

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
```

