Here's a Java implementation for the Stripe account management functionality based on your requirements:

```java
// AccountService.java
import com.stripe.Stripe;
import com.stripe.exception.*;
import com.stripe.model.*;
import com.stripe.param.*;

public class AccountService {
    private static final String STRIPE_SECRET_KEY = "your_stripe_secret_key";

    static {
        Stripe.apiKey = STRIPE_SECRET_KEY;
    }

    // Endpoint: POST /account-update/{customer_id}
    public String updateAccountInfo(String customerId, String name, String email, String paymentMethodId) {
        try {
            // Retrieve customer
            Customer customer = Customer.retrieve(customerId);

            // Check if email already exists for another customer
            CustomerListParams params = CustomerListParams.builder()
                .setEmail(email)
                .build();

            CustomerCollection customers = Customer.list(params);
            for (Customer c : customers.getData()) {
                if (!c.getId().equals(customerId)) {
                    return "customer-exists-error"; // Return error identifier
                }
            }

            // Update customer information
            CustomerUpdateParams.Builder updateParamsBuilder = CustomerUpdateParams.builder()
                .setName(name)
                .setEmail(email);

            // Update payment method if provided
            if (paymentMethodId != null && !paymentMethodId.isEmpty()) {
                updateParamsBuilder.setInvoiceSettings(
                    CustomerUpdateParams.InvoiceSettings.builder()
                        .setDefaultPaymentMethod(paymentMethodId)
                        .build()
                );
            }

            Customer updatedCustomer = customer.update(updateParamsBuilder.build());

            // Return success
            return "success";

        } catch (Exception e) {
            return "error: " + e.getMessage();
        }
    }

    // Endpoint: POST /delete-account/{customer_id}
    public Object deleteAccount(String customerId) {
        try {
            // Check for uncaptured payments
            PaymentIntentListParams listParams = PaymentIntentListParams.builder()
                .setCustomer(customerId)
                .setStatuses(Arrays.asList("requires_payment_method", "requires_confirmation", "requires_action"))
                .build();

            PaymentIntentCollection paymentIntents = PaymentIntent.list(listParams);

            // If there are uncaptured payments, return their IDs
            if (paymentIntents.getData().size() > 0) {
                List<String> paymentIntentIds = new ArrayList<>();
                for (PaymentIntent intent : paymentIntents.getData()) {
                    paymentIntentIds.add(intent.getId());
                }
                return paymentIntentIds;
            }

            // No uncaptured payments, safe to delete
            Customer customer = Customer.retrieve(customerId);
            customer.delete();

            return new HashMap<String, Object>() {{
                put("deleted", true);
            }};

        } catch (Exception e) {
            Map<String, Object> errorResponse = new HashMap<>();
            errorResponse.put("error", e.getMessage());
            return errorResponse;
        }
    }
}

// AccountController.java (Spring Boot example)
@RestController
@RequestMapping("/api")
public class AccountController {
    private final AccountService accountService;

    public AccountController(AccountService accountService) {
        this.accountService = accountService;
    }

    @PostMapping("/account-update/{customerId}")
    public ResponseEntity<String> updateAccount(@PathVariable String customerId,
                                               @RequestBody AccountUpdateRequest request) {
        String result = accountService.updateAccountInfo(customerId, request.getName(),
                                                        request.getEmail(), request.getPaymentMethodId());

        if ("customer-exists-error".equals(result)) {
            return ResponseEntity.badRequest().body("Customer email already exists");
        }

        return ResponseEntity.ok("Account updated successfully");
    }

    @PostMapping("/delete-account/{customerId}")
    public ResponseEntity<Object> deleteAccount(@PathVariable String customerId) {
        Object result = accountService.deleteAccount(customerId);

        if (result instanceof List) {
            // Return list of uncaptured payment intents
            return ResponseEntity.status(HttpStatus.CONFLICT).body(result);
        } else if (result instanceof Map) {
            // Return success response
            return ResponseEntity.ok(result);
        } else {
            // Return error response
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(result);
        }
    }
}

